func scopeExitCode(o scopeOutcome) int {
	if o.Err != nil {
		return MapExit(o.Err)
	}
	if o.Summary.Outcome.ExitCode != 0 {
		return o.Summary.Outcome.ExitCode
	}
	return 0
}

