	// atomic critical section a concurrent sync cannot interleave. The caller
	// owns release. Default false: Sync acquires and releases the lock itself.
	RunLockHeld bool
}

// Request is one sync/validate invocation. The caller is responsible for
// discovering adapters and materializing+decoding the IR (see Materialize)
// so the engine itself performs no network or git I/O — it is the pure
// write-pipeline orchestrator.
type Request struct {
	// Root is the opened workspace root; all staging/swap/ledger writes
	// go through it.
	Root *fsroot.Root

	// WorkspacePath is the absolute workspace path, for the report header.
	WorkspacePath string

	// Scope is the hierarchy level being emitted ("user", "project",
	// "workspace", "directory", or legacy "global" alias), passed to each
	// adapter session so it can pick scope-appropriate output paths. Empty ⇒
