	if err != nil {
		return updateResolution{}, fmt.Errorf("canonicalize: %w", err)
	}
	loc, err := cache.Resolve(canonical, cache.ResolveOptions{Override: m.Cache.Override})
	if err != nil {
		return updateResolution{}, fmt.Errorf("resolve cache: %w", err)
	}
	ref := m.Canonical.Ref
	refName := ref
	fromHEAD := false
	if ref == "" {
