func userWarnKinds(outcomes []scopeOutcome, target string) map[ir.Kind]bool {
	got := map[ir.Kind]bool{}
	for _, o := range outcomes {
		if o.Scope.Level != hierarchy.LevelUser {
			continue
		}
		for _, w := range o.Warnings {
			if w.Target == target {
				got[w.Kind] = true
			}
		}
	}
	return got
}

